// Drop into a Code node immediately AFTER 'Dedup check (Bravoro)'.
// It reads the dedup-check response and the original leads array,
// and returns only the leads with verdict === 'unique'.

const dedup = $input.first().json;
if (!dedup || !Array.isArray(dedup.results)) {
  // Fail-open: if dedup-check returned an unexpected shape, pass everything
  // through to enrichment rather than dropping leads.
  return $('previous-node').first().json.leads.map(l => ({ json: l }));
}
const leads = $('previous-node').first().json.leads;
return dedup.results
  .filter(r => r.verdict === 'unique')
  .map(r => ({ json: leads[r.lead_index] }));
